    override fun connectWifi(ipAddress: String) {
        runCatching { usbPort?.close() }
        usbPort = null
        usbDeviceName = null
        val cleanIp = ipAddress.trim()
            .removePrefix("http://")
            .removePrefix("https://")
            .substringBefore("/")
            .substringBefore(":")
        if (cleanIp.isBlank()) {
            logError("WIFI", "Invalid IP/host")
            _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
            return
        }
        targetIp = cleanIp
        transport = Transport.WIFI
        _connection.value = ConnectionState(ConnectionState.Status.CONNECTING, ipAddress)

        scope.launch {
            try {
                val request = Request.Builder().url(baseUrl("/api/status")).build()
                client.newCall(request).execute().use { response ->
                    if (response.isSuccessful) {
                        val body = response.body?.string().orEmpty()
                        val obj = JSONObject(body)
                        val deviceName = obj.optString("name", cleanIp)
                        _connection.value = ConnectionState(ConnectionState.Status.CONNECTED, deviceName)
                        logInfo("WIFI", "Connected to $cleanIp:8080")
                        consolePollFailStreak = 0
                        startConsolePolling()
                        startPacketPolling()
                    } else {
                        throw IOException("Failed to connect: ${response.code}")
                    }
                }
            } catch (e: Exception) {
                _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
                logError("WIFI", "Connection failed: ${e.message}")
            }
        }
    }

    override fun connectUsb() {
        targetIp = null
        consolePollJob?.cancel()
        packetPollJob?.cancel()
        lastConsoleSeq = 0
        lastPacketSeq = 0
        usbRxBuf.clear()
        _connection.value = ConnectionState(ConnectionState.Status.CONNECTING, "USB")

        scope.launch {
            try {
                val drivers = UsbSerialProber.getDefaultProber().findAllDrivers(usbManager)
                if (drivers.isEmpty()) {
                    _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
                    logError("USB", "No USB serial device found. Connect CYD via OTG USB-C.")
                    return@launch
                }
                val driver = drivers.first()
                val device = driver.device
                if (!usbManager.hasPermission(device)) {
                    val pi = PendingIntent.getBroadcast(
                        appContext,
                        0,
                        Intent("com.example.cydcompanion.USB_PERMISSION"),
                        PendingIntent.FLAG_IMMUTABLE
                    )
                    usbManager.requestPermission(device, pi)
                    _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
                    logError("USB", "Grant USB permission then tap USB Link again.")
                    return@launch
                }
                val conn = usbManager.openDevice(device)
                if (conn == null) {
                    _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
                    logError("USB", "Failed to open USB device.")
                    return@launch
                }
                val port = driver.ports.firstOrNull()
                if (port == null) {
                    conn.close()
                    _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
                    logError("USB", "No serial port on USB device.")
                    return@launch
                }
                port.open(conn)
                port.setParameters(115200, 8, UsbSerialPort.STOPBITS_1, UsbSerialPort.PARITY_NONE)
                runCatching { port.setDTR(true); port.setRTS(true) }
                usbPort = port
                transport = Transport.USB
                usbDeviceName = device.productName ?: device.deviceName ?: "CYD-USB"
                val status = usbRpc("status")
                val name = status?.optString("name")?.takeIf { it.isNotBlank() } ?: usbDeviceName
                _connection.value = ConnectionState(ConnectionState.Status.CONNECTED, name)
                logInfo("USB", "Connected over USB serial: $name")
                startConsolePolling()
                startPacketPolling()
            } catch (e: Exception) {
                runCatching { usbPort?.close() }
                usbPort = null
                transport = Transport.NONE
                _connection.value = ConnectionState(ConnectionState.Status.DISCONNECTED, null)
                logError("USB", "Connection failed: ${e.message}")
            }
        }
    }

    override fun sendControlCommand(cmd: String, params: Map<String, Any>) {
        if (transport == Transport.USB) {
            scope.launch {
                val payload = JSONObject().apply {
                    put("name", cmd)
                    params.forEach { (k, v) ->
                        when (v) {
                            is Boolean -> put(k, v)
                            is Number -> put(k, v)
                            else -> put(k, v.toString())
                        }
                    }
                }
                val response = usbRpc("control", payload)
                if (response?.optBoolean("ok", false) == true) {
                    logInfo("USB", "CTRL $cmd OK")
                } else {
                    logError("USB", "CTRL $cmd failed: ${response?.optString("error", "no response")}")
                }
            }
            return
        }
        if (targetIp == null) return
        scope.launch {
            val json = JSONObject().apply {
                put("cmd", cmd)
                params.forEach { (k, v) -> put(k, v) }
            }
            val body = json.toString().toRequestBody("application/json".toMediaType())
            val request = Request.Builder().url(baseUrl("/api/control")).post(body).build()
            try {
                client.newCall(request).execute().use { response ->
                    val payload = response.body?.string().orEmpty()
                    if (response.isSuccessful) logInfo("CMD", "$cmd OK")
                    else logError("CMD", "$cmd failed: ${response.code} $payload")
                }
            } catch (e: Exception) {
                logError("CMD", "Request error: ${e.message}")
            }
        }
    }

