    override suspend fun downloadFileBytes(file: CydFile): ByteArray? = withContext(Dispatchers.IO) {
        if (file.isDirectory) return@withContext null
        if (transport == Transport.USB) {
            return@withContext downloadFileBytesUsb(file)
        }
        val ip = targetIp ?: return@withContext null

        val (fsToken, fsPath) = splitRepoPath(file.path)
        val apiUrl = HttpUrl.Builder()
            .scheme("http")
            .host(ip)
            .port(8080)
            .addPathSegment("download")
            .addQueryParameter("fs", fsToken)
            .addQueryParameter("path", fsPath)
            .build()

        // Newer app protocol first
        val fromApi = try {
            client.newCall(Request.Builder().url(apiUrl).build()).execute().use { response ->
                if (!response.isSuccessful) {
                    null
                } else {
                    response.body?.bytes()
                }
            }
        } catch (_: Exception) {
            null
        }
        if (fromApi != null) return@withContext fromApi

        // Firmware-compatible SD endpoint fallback
        if (!fsToken.equals("sd", true)) {
            logError("FS", "Download bytes failed: unsupported fs=$fsToken on this firmware")
            return@withContext null
        }
        val sdUrl = HttpUrl.Builder()
            .scheme("http")
            .host(ip)
            .port(8080)
            .addPathSegment("sd")
            .addPathSegment("get")
            .addQueryParameter("path", normalizeFsPath(fsPath))
            .build()

        return@withContext try {
            client.newCall(Request.Builder().url(sdUrl).build()).execute().use { response ->
                if (!response.isSuccessful) {
                    logError("FS", "Download bytes failed: HTTP ${response.code}")
                    null
                } else {
                    response.body?.bytes()
                }
            }
        } catch (e: Exception) {
            logError("FS", "Download bytes error: ${e.message}")
            null
        }
    }

    override suspend fun listFilesRecursive(path: String): List<CydFile> = withContext(Dispatchers.IO) {
        val result = mutableListOf<CydFile>()
        val queue = mutableListOf(path)
        val visited = mutableSetOf<String>()

        while (queue.isNotEmpty()) {
            val currentPath = queue.removeAt(0)
            if (currentPath in visited) continue
            visited.add(currentPath)
            val children = listFilesCompat(currentPath)
            children.forEach { file ->
                result.add(file)
                if (file.isDirectory) queue.add(file.path)
            }
        }
        result
    }

