    override fun otaUpload(file: File): Flow<Float> = callbackFlow {
        if (targetIp == null) throw IOException("Not connected via WiFi")
        logInfo("OTA", "Starting upload: ${file.name} (${file.length()} bytes)")
        trySend(0.0f)

        val requestBody = MultipartBody.Builder()
            .setType(MultipartBody.FORM)
            .addFormDataPart("firmware", file.name, file.asRequestBody("application/octet-stream".toMediaType()))
            .build()

        val request = Request.Builder()
            .url(baseUrl("/ota"))
            .post(requestBody)
            .build()

        val call = client.newCall(request)

        scope.launch {
            try {
                val response = withContext(Dispatchers.IO) { call.execute() }
                if (response.isSuccessful) {
                    logInfo("OTA", "Upload complete! Device is rebooting...")
                    trySend(1.0f)
                } else {
                    logError("OTA", "Upload failed: ${response.code}")
                    close(IOException("Server returned ${response.code}"))
                }
            } catch (e: Exception) {
                logError("OTA", "OTA Error: ${e.message}")
                close(e)
            } finally {
                channel.close()
            }
        }

        awaitClose { call.cancel() }
    }

    private fun logInfo(tag: String, msg: String) {
        _console.tryEmit(ConsoleLine(ts = nowTs(), level = ConsoleLine.Level.INFO, tag = tag, msg = msg))
    }

    private fun logError(tag: String, msg: String) {
        _console.tryEmit(ConsoleLine(ts = nowTs(), level = ConsoleLine.Level.ERROR, tag = tag, msg = msg))
    }

    private fun nowTs(): String = SimpleDateFormat("HH:mm:ss", Locale.US).format(Date())

    private fun startConsolePolling() {
        consolePollJob?.cancel()
        lastConsoleSeq = 0
        consolePollJob = scope.launch {
            while (isActive && targetIp != null && _connection.value.status == ConnectionState.Status.CONNECTED) {
                pollConsoleOnce()
                delay(450)
            }
        }
    }

    private fun startPacketPolling() {
        packetPollJob?.cancel()
        lastPacketSeq = 0
        packetPollJob = scope.launch {
            while (isActive && targetIp != null && _connection.value.status == ConnectionState.Status.CONNECTED) {
                pollPacketsOnce()
                delay(260)
            }
        }
    }

    private suspend fun pollConsoleOnce() {
        if (transport == Transport.USB) {
            pollConsoleOnceUsb()
            return
        }
        val ip = targetIp ?: return
        val url = HttpUrl.Builder()
            .scheme("http")
            .host(ip)
            .port(8080)
            .addPathSegment("api")
            .addPathSegment("console")
            .addQueryParameter("since", lastConsoleSeq.toString())
            .addQueryParameter("limit", "80")
            .build()

        try {
            client.newCall(Request.Builder().url(url).build()).execute().use { response ->
                if (!response.isSuccessful) return@use
                consolePollFailStreak = 0
                val body = response.body?.string().orEmpty()
                val obj = JSONObject(body)
                val lines = obj.optJSONArray("lines") ?: return@use
                for (i in 0 until lines.length()) {
                    val line = lines.getJSONObject(i)
                    val seq = line.optLong("seq", 0L)
                    if (seq > lastConsoleSeq) lastConsoleSeq = seq
                    val level = when (line.optString("level", "INFO").uppercase(Locale.US)) {
                        "ERROR" -> ConsoleLine.Level.ERROR
                        "WARN" -> ConsoleLine.Level.WARN
                        else -> ConsoleLine.Level.INFO
                    }
                    _console.tryEmit(
                        ConsoleLine(
                            ts = nowTs(),
                            level = level,
                            tag = line.optString("tag", "WEB"),
                            msg = line.optString("msg", "")
                        )
                    )
                }
            }
        } catch (_: Exception) {
            // Keep polling; transient network failures are expected.
            consolePollFailStreak++
            if (consolePollFailStreak == 6) {
                logError(
                    "WIFI",
                    "Console link unstable. If sniffing, connect phone WiFi to CYD-LIVE and use 192.168.4.1"
                )
            }
        }
    }

    private suspend fun pollPacketsOnce() {
        if (transport == Transport.USB) {
            pollPacketsOnceUsb()
            return
        }
        val ip = targetIp ?: return
        val url = HttpUrl.Builder()
            .scheme("http")
            .host(ip)
            .port(8080)
            .addPathSegment("api")
            .addPathSegment("packets")
            .addQueryParameter("since", lastPacketSeq.toString())
            .addQueryParameter("limit", "150")
            .build()

        try {
            client.newCall(Request.Builder().url(url).build()).execute().use { response ->
                if (!response.isSuccessful) return@use
                val body = response.body?.string().orEmpty()
                val obj = JSONObject(body)
                val lines = obj.optJSONArray("lines") ?: return@use
                for (i in 0 until lines.length()) {
                    val line = lines.getJSONObject(i)
                    val seq = line.optLong("seq", 0L)
                    if (seq > lastPacketSeq) lastPacketSeq = seq
                    _packets.tryEmit(
                        PacketLine(
                            seq = seq,
                            ms = line.optLong("ms", 0L),
                            type = line.optInt("type", -1),
                            subtype = line.optInt("subtype", -1),
                            len = line.optInt("len", 0),
                            rssi = line.optInt("rssi", -127),
                            channel = line.optInt("ch", 0),
                            src = line.optString("src", ""),
                            dst = line.optString("dst", ""),
                            bssid = line.optString("bssid", "")
                        )
                    )
                }
            }
        } catch (_: Exception) {
            // Keep polling; transient failures are expected.
        }
    }

    private fun splitRepoPath(repoPathRaw: String): Pair<String, String> {
        var p = repoPathRaw.trim()
        if (p.isEmpty()) p = "/sd"
        if (!p.startsWith("/")) p = "/$p"

        return if (p.equals("/lfs", true) || p.startsWith("/lfs/")) {
            val inner = p.removePrefix("/lfs").ifBlank { "/" }
            "lfs" to normalizeFsPath(inner)
        } else {
            val inner = p.removePrefix("/sd").ifBlank { "/" }
            "sd" to normalizeFsPath(inner)
        }
    }

    private fun toRepoPath(fsTokenRaw: String, fsPathRaw: String): String {
        val fsPrefix = if (fsTokenRaw.equals("lfs", true)) "/lfs" else "/sd"
        val fsPath = normalizeFsPath(fsPathRaw)
        return if (fsPath == "/") fsPrefix else fsPrefix + fsPath
    }

    private fun normalizeFsPath(pathRaw: String): String {
        var p = pathRaw.trim()
        if (p.isEmpty()) p = "/"
        if (!p.startsWith("/")) p = "/$p"
        return p
    }

    private fun baseUrl(path: String): String {
        val ip = targetIp ?: "0.0.0.0"
        return "http://$ip:8080$path"
    }

