    private suspend fun listFilesCompat(path: String): List<CydFile> = withContext(Dispatchers.IO) {
        if (transport == Transport.USB) {
            return@withContext listFilesViaUsb(path)
        }
        val ip = targetIp ?: return@withContext emptyList()
        val (fsToken, fsPath) = splitRepoPath(path)

        // Preferred API (if firmware supports it)
        listFilesViaApi(ip, fsToken, fsPath)?.let { return@withContext it }

        // Firmware fallback: SD file-manager HTML
        if (!fsToken.equals("sd", true)) {
            logError("FS", "List failed: fs=$fsToken unsupported by current firmware")
            return@withContext emptyList()
        }
        return@withContext listFilesViaSdHtml(ip, fsPath)
    }

    private fun listFilesViaApi(ip: String, fsToken: String, fsPath: String): List<CydFile>? {
        val url = HttpUrl.Builder()
            .scheme("http")
            .host(ip)
            .port(8080)
            .addPathSegment("api")
            .addPathSegment("list")
            .addQueryParameter("fs", fsToken)
            .addQueryParameter("path", fsPath)
            .build()

        return try {
            client.newCall(Request.Builder().url(url).build()).execute().use { response ->
                if (!response.isSuccessful) return null
                val jsonStr = response.body?.string().orEmpty()
                val root = JSONObject(jsonStr)
                val items = root.optJSONArray("items") ?: return emptyList()
                val out = mutableListOf<CydFile>()
                for (i in 0 until items.length()) {
                    val item = items.getJSONObject(i)
                    val itemPath = item.optString("path", "/")
                    val itemFs = root.optString("fs", fsToken)
                    val name = item.optString("name").ifBlank {
                        itemPath.substringAfterLast('/', itemPath)
                    }
                    out.add(
                        CydFile(
                            name = name,
                            path = toRepoPath(itemFs, itemPath),
                            isDirectory = item.optBoolean("dir", false),
                            size = item.optLong("size", 0L)
                        )
                    )
                }
                out
            }
        } catch (_: Exception) {
            null
        }
    }

    private fun listFilesViaSdHtml(ip: String, fsPath: String): List<CydFile> {
        val normalized = normalizeFsPath(fsPath)
        val url = HttpUrl.Builder()
            .scheme("http")
            .host(ip)
            .port(8080)
            .addPathSegment("sd")
            .addQueryParameter("path", normalized)
            .build()

        return try {
            client.newCall(Request.Builder().url(url).build()).execute().use { response ->
                if (!response.isSuccessful) {
                    logError("FS", "List failed: HTTP ${response.code}")
                    return emptyList()
                }
                val html = response.body?.string().orEmpty()
                parseSdHtmlDirectoryRows(html)
            }
        } catch (e: Exception) {
            logError("FS", "List failed: ${e.message}")
            emptyList()
        }
    }

    private fun parseSdHtmlDirectoryRows(html: String): List<CydFile> {
        val rows = Regex(
            "<tr><td>(.*?)</td><td>(dir|file)</td><td>(\\d+)</td><td>(.*?)</td></tr>",
            setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL)
        ).findAll(html)

        val out = mutableListOf<CydFile>()
        rows.forEach { m ->
            val name = decodeHtmlEntities(m.groupValues[1]).trim()
            val type = m.groupValues[2].lowercase(Locale.US)
            val size = m.groupValues[3].toLongOrNull() ?: 0L
            val actions = m.groupValues[4]

            val pathEncoded = if (type == "dir") {
                Regex("href='/sd\\?path=([^']+)'", RegexOption.IGNORE_CASE).find(actions)?.groupValues?.getOrNull(1)
            } else {
                Regex("href='/sd/get\\?path=([^']+)'", RegexOption.IGNORE_CASE).find(actions)?.groupValues?.getOrNull(1)
            } ?: return@forEach

            val fullPath = decodeUrl(pathEncoded)
            if (fullPath.isBlank() || fullPath == "/") return@forEach
            out.add(
                CydFile(
                    name = if (name.isBlank()) fullPath.substringAfterLast('/', fullPath) else name,
                    path = toRepoPath("sd", fullPath),
                    isDirectory = type == "dir",
                    size = size
                )
            )
        }
        return out
    }

    private fun decodeUrl(raw: String): String =
        runCatching { URLDecoder.decode(raw, Charsets.UTF_8.name()) }.getOrElse { raw }

    private fun decodeHtmlEntities(raw: String): String {
        return raw
            .replace("&lt;", "<")
            .replace("&gt;", ">")
            .replace("&amp;", "&")
            .replace("&quot;", "\"")
            .replace("&#39;", "'")
    }

    private suspend fun listFilesViaUsb(path: String): List<CydFile> = withContext(Dispatchers.IO) {
        val (fsToken, fsPath) = splitRepoPath(path)
        if (!fsToken.equals("sd", true)) {
            logError("USB", "Only /sd is supported over USB at this time.")
            return@withContext emptyList()
        }
        val rsp = usbRpc("list", JSONObject().put("path", fsPath)) ?: return@withContext emptyList()
        if (!rsp.optBoolean("ok", false)) return@withContext emptyList()
        val items = rsp.optJSONArray("items") ?: return@withContext emptyList()
        val out = mutableListOf<CydFile>()
        for (i in 0 until items.length()) {
            val item = items.optJSONObject(i) ?: continue
            val fullPath = item.optString("path", "")
            val name = item.optString("name", fullPath.substringAfterLast('/', fullPath))
            out.add(
                CydFile(
                    name = name,
                    path = toRepoPath("sd", fullPath),
                    isDirectory = item.optBoolean("dir", false),
                    size = item.optLong("size", 0L)
                )
            )
        }
        out
    }

    private suspend fun downloadFileBytesUsb(file: CydFile): ByteArray? = withContext(Dispatchers.IO) {
        val (fsToken, fsPath) = splitRepoPath(file.path)
        if (!fsToken.equals("sd", true)) {
            logError("USB", "Download supports only /sd paths on USB.")
            return@withContext null
        }
        val begin = usbRpc("download_begin", JSONObject().put("path", fsPath)) ?: return@withContext null
        if (!begin.optBoolean("ok", false)) return@withContext null
        val token = begin.optString("token", "")
        val total = begin.optLong("size", 0L)
        if (token.isBlank()) return@withContext null

        val out = ByteArrayOutputStream(if (total > 0) total.toInt() else 4096)
        var offset = 0L
        while (true) {
            val chunk = usbRpc(
                "download_chunk",
                JSONObject()
                    .put("token", token)
                    .put("offset", offset)
                    .put("max", 192)
            ) ?: break
            if (!chunk.optBoolean("ok", false)) break
            val hex = chunk.optString("hex", "")
            val bytes = decodeHex(hex)
            if (bytes.isNotEmpty()) out.write(bytes)
            val eof = chunk.optBoolean("eof", false)
            offset = chunk.optLong("offset", offset) + bytes.size
            if (eof) break
            if (bytes.isEmpty()) break
        }
        usbRpc("download_end", JSONObject().put("token", token))
        out.toByteArray()
    }

    private suspend fun pollConsoleOnceUsb() {
        val rsp = usbRpc(
            "console",
            JSONObject()
                .put("since", lastConsoleSeq)
                .put("limit", 80)
        ) ?: return
        val lines = rsp.optJSONArray("lines") ?: return
        for (i in 0 until lines.length()) {
            val line = lines.optJSONObject(i) ?: continue
            val seq = line.optLong("seq", 0L)
            if (seq > lastConsoleSeq) lastConsoleSeq = seq
            val level = when (line.optString("level", "INFO").uppercase(Locale.US)) {
                "ERROR" -> ConsoleLine.Level.ERROR
                "WARN" -> ConsoleLine.Level.WARN
                else -> ConsoleLine.Level.INFO
            }
            _console.tryEmit(
                ConsoleLine(
                    ts = nowTs(),
                    level = level,
                    tag = line.optString("tag", "USB"),
                    msg = line.optString("msg", "")
                )
            )
        }
    }

    private suspend fun pollPacketsOnceUsb() {
        val rsp = usbRpc(
            "packets",
            JSONObject()
                .put("since", lastPacketSeq)
                .put("limit", 150)
        ) ?: return
        val lines = rsp.optJSONArray("lines") ?: return
        for (i in 0 until lines.length()) {
            val line = lines.optJSONObject(i) ?: continue
            val seq = line.optLong("seq", 0L)
            if (seq > lastPacketSeq) lastPacketSeq = seq
            _packets.tryEmit(
                PacketLine(
                    seq = seq,
                    ms = line.optLong("ms", 0L),
                    type = line.optInt("type", -1),
                    subtype = line.optInt("subtype", -1),
                    len = line.optInt("len", 0),
                    rssi = line.optInt("rssi", -127),
                    channel = line.optInt("ch", 0),
                    src = line.optString("src", ""),
                    dst = line.optString("dst", ""),
                    bssid = line.optString("bssid", "")
                )
            )
        }
    }

    private suspend fun usbRpc(cmd: String, params: JSONObject = JSONObject(), timeoutMs: Int = 4000): JSONObject? {
        val port = usbPort ?: return null
        return usbRpcMutex.withLock {
            val reqId = usbRpcId++
            val req = JSONObject().apply {
                put("id", reqId)
                put("cmd", cmd)
                val names = params.keys()
                while (names.hasNext()) {
                    val k = names.next()
                    put(k, params.get(k))
                }
            }
            val line = req.toString() + "\n"
            try {
                port.write(line.toByteArray(Charsets.UTF_8), 1200)
            } catch (e: Exception) {
                logError("USB", "Write failed: ${e.message}")
                return@withLock null
            }

            val deadline = System.currentTimeMillis() + timeoutMs
            val tmp = ByteArray(512)
            while (System.currentTimeMillis() < deadline) {
                val parsed = drainUsbJsonLines(reqId)
                if (parsed != null) return@withLock parsed
                val n = try {
                    port.read(tmp, 180)
                } catch (_: Exception) {
                    0
                }
                if (n > 0) {
                    usbRxBuf.append(String(tmp, 0, n, Charsets.UTF_8))
                    val again = drainUsbJsonLines(reqId)
                    if (again != null) return@withLock again
                }
            }
            logError("USB", "RPC timeout for '$cmd'")
            null
        }
    }

    private fun drainUsbJsonLines(expectId: Int): JSONObject? {
        while (true) {
            val idx = usbRxBuf.indexOf("\n")
            if (idx < 0) return null
            val line = usbRxBuf.substring(0, idx).trim()
            usbRxBuf.delete(0, idx + 1)
            if (line.isBlank()) continue
            val obj = runCatching { JSONObject(line) }.getOrNull() ?: continue
            if (obj.optInt("id", -1) == expectId) return obj
        }
    }

    private fun decodeHex(hexRaw: String): ByteArray {
        val hex = hexRaw.trim()
        if (hex.isEmpty() || hex.length % 2 != 0) return ByteArray(0)
        val out = ByteArray(hex.length / 2)
        var i = 0
        while (i < hex.length) {
            val b = hex.substring(i, i + 2).toIntOrNull(16) ?: return ByteArray(0)
            out[i / 2] = b.toByte()
            i += 2
        }
        return out
    }

    // -------------------------------------------------------------------------
    // AI-Assisted Pentesting (Phase 2)
    // -------------------------------------------------------------------------

    override suspend fun fetchAiFrames(): TargetProfile? {
        if (transport == Transport.USB) {
            val rsp = usbRpc("ai_frames") ?: return null
            return parseAiFramesResponse(rsp.toString())
        }
        val ip = targetIp ?: return null
        return kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.IO) {
            try {
                val request = Request.Builder().url(baseUrl("/api/ai/frames")).build()
                client.newCall(request).execute().use { response ->
                    if (!response.isSuccessful) return@withContext null
                    val body = response.body?.string() ?: return@withContext null
                    parseAiFramesResponse(body)
                }
            } catch (e: Exception) {
                logError("AI", "fetchAiFrames failed: ${e.message}")
                null
            }
        }
    }

    private fun parseAiFramesResponse(json: String): TargetProfile? {
        return try {
            val root    = JSONObject(json)
            if (!root.optBoolean("ok", false)) return null
            val tgtObj  = root.optJSONObject("target") ?: return null
            val ssid    = tgtObj.optString("ssid", "")
            val bssid   = tgtObj.optString("bssid", "")
            val apOui   = tgtObj.optString("oui",   bssid.take(8))
            val channel = tgtObj.optInt("channel", 0)
            val rssi    = tgtObj.optInt("rssi", -99)
            val auth    = tgtObj.optString("auth", "Unknown")

            val apVendor = OuiDatabase.resolve(apOui)

            // Parse handshake list — take the first valid one for the profile
            val hsArr = root.optJSONArray("handshakes") ?: return null
            var bestMask = 0
            var clientMac: String? = null
            var staOui: String? = null
            var staVendor: String? = null
            val frames = mutableListOf<EapolFrameInfo>()

            for (i in 0 until hsArr.length()) {
                val hs = hsArr.getJSONObject(i)
                val mask = hs.optInt("mask", 0)
                if (mask == 0) continue
                if (mask.countOneBits() <= bestMask.countOneBits()) continue

                bestMask  = mask
                clientMac = hs.optString("station").takeIf { it.isNotBlank() }
                staOui    = hs.optString("sta_oui").takeIf { it.isNotBlank() }
                staVendor = staOui?.let { OuiDatabase.resolve(it) }

                frames.clear()
                val frArr = hs.optJSONArray("frames") ?: continue
                for (j in 0 until frArr.length()) {
                    val fr = frArr.getJSONObject(j)
                    val msgNum    = fr.optInt("msg", j + 1)
                    val eapolHex  = fr.optString("eapol_hex", "")
                    val frameHex  = fr.optString("frame_hex", "")
                    val fRssi     = fr.optInt("rssi", -99)
                    val ts        = fr.optLong("ts", 0L)
                    FrameParser.parseEapol(msgNum, eapolHex, frameHex, fRssi, ts)
                        ?.let { frames.add(it) }
                }
            }

            if (bestMask == 0) return null

            TargetProfile(
                ssid          = ssid,
                bssid         = bssid,
                apOui         = apOui,
                apVendor      = apVendor,
                clientMac     = clientMac,
                staOui        = staOui,
                staVendor     = staVendor,
                channel       = channel,
                rssi          = rssi,
                auth          = auth,
                eapolMask     = bestMask,
                hasValidPair  = frames.any { it.hasMic && !it.hasAck } &&
                                frames.any { !it.hasMic &&  it.hasAck },
                frames        = frames
            )
        } catch (e: Exception) {
            logError("AI", "parseAiFramesResponse error: ${e.message}")
            null
        }
    }

    override suspend fun injectRaw(channel: Int, frameHex: String): Boolean {
        if (transport == Transport.USB) {
            val rsp = usbRpc(
                "ai_inject_raw",
                JSONObject().put("channel", channel).put("frame", frameHex)
            )
            return rsp?.optBoolean("ok", false) == true
        }
        val ip = targetIp ?: return false
        return kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.IO) {
            var result = false
            InjectionDispatcher(ip).injectRaw(channel, frameHex) { ok, msg ->
                result = ok
                if (ok) logInfo("AI", msg) else logError("AI", msg)
            }
            result
        }
    }

    override suspend fun injectDeauth(
        bssid: String,
        client: String,
        reason: Int,
        count: Int,
        channel: Int
    ): Boolean {
        if (transport == Transport.USB) {
            val rsp = usbRpc(
                "ai_inject_deauth",
                JSONObject()
                    .put("bssid", bssid)
                    .put("client", client)
                    .put("reason", reason)
                    .put("count", count)
                    .put("channel", channel)
            )
            return rsp?.optBoolean("ok", false) == true
        }
        val ip = targetIp ?: return false
        return kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.IO) {
            var result = false
            InjectionDispatcher(ip).injectDeauth(bssid, client, reason, count, channel) { ok, msg ->
                result = ok
                if (ok) logInfo("AI", msg) else logError("AI", msg)
            }
            result
        }
    }

    override suspend fun fetchInjectionTelemetry(): InjectionTelemetry? {
        if (transport == Transport.USB) {
            val obj = usbRpc("status") ?: return null
            val yoink = obj.optJSONObject("yoink")
            return InjectionTelemetry(
                packets = obj.optLong("packets", 0L),
                beacons = obj.optLong("beacons", 0L),
                handshakes = obj.optLong("handshakes", 0L),
                sniffActive = obj.optBoolean("sniffActive", false),
                lockChannel = obj.optBoolean("lockChannel", false),
                yoinkState = yoink?.optString("state"),
                yoinkTarget = yoink?.optString("target"),
                yoinkDeauths = yoink?.optLong("deauths"),
                yoinkHandshakes = yoink?.optLong("hs")
            )
        }
        if (targetIp == null) return null
        return kotlinx.coroutines.withContext(kotlinx.coroutines.Dispatchers.IO) {
            try {
                val request = Request.Builder().url(baseUrl("/api/status")).build()
                client.newCall(request).execute().use { response ->
                    if (!response.isSuccessful) return@withContext null
                    val body = response.body?.string() ?: return@withContext null
                    val obj = JSONObject(body)
                    val yoink = obj.optJSONObject("yoink")
                    InjectionTelemetry(
                        packets = obj.optLong("packets", 0L),
                        beacons = obj.optLong("beacons", 0L),
                        handshakes = obj.optLong("handshakes", 0L),
                        sniffActive = obj.optBoolean("sniffActive", false),
                        lockChannel = obj.optBoolean("lockChannel", false),
                        yoinkState = yoink?.optString("state"),
                        yoinkTarget = yoink?.optString("target"),
                        yoinkDeauths = yoink?.optLong("deauths"),
                        yoinkHandshakes = yoink?.optLong("hs")
                    )
                }
            } catch (e: Exception) {
                logError("AI", "fetchInjectionTelemetry failed: ${e.message}")
                null
            }
        }
    }
